var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"장로님, 갑자기 그게 무슨 말씀이시죠?","JPN":"長老、急に何をおっしゃるのですか？","ENG":"Elder, what are you talking about?","TWN":"長老，為何突然召聚大家？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"말씀드린 그대로입니다.","JPN":"申し上げたとおりです。","ENG":"It’s just as I said.","TWN":"就如同我剛說的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"나나하라 당주를 다시 선별할 필요성이 있다고 판단해, 이를 의결에 부치고자 합니다.","JPN":"七原家の当主を再度選出する必要があると判断し、\\nこれを議題にしたいと思います。","ENG":"I would like to propose that we reelect the leader of the Nanahara family.","TWN":"我認爲有必要重新選出七原堂主，因此想請大家表決。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"나나하라의 당주는 직계 후손이어야만 합니다. 그건 기본 중의 기본이지 않습니까?","JPN":"七原家の当主は直系の子孫でなければなりません。それは絶対に守るべきしきたりではありませんか？","ENG":"The leader of the Nanahara family must be from the direct line. It’s obvious.","TWN":"七原的堂主必須是直系後裔，這是最基本的不是嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"누구보다 연합의 전통을 중히 여기시는 장로께서 모르실 리가 없을 텐데요.","JPN":"誰よりも連合の伝統を重んじてらっしゃった長老がご存じないはずがありません。","ENG":"You are an elder, so you should be aware of this.","TWN":"長老比任何人都還重視聯盟的傳統，不可能不知道吧？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"저는 전통의 지침을 따르고 있을 뿐입니다.","JPN":"私は伝統の指針に従っているだけです。","ENG":"I am only following the tradition.","TWN":"我只是遵照傳統的規矩而已。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"<color=#ffd34c>자격이 부족한 당주는, 다른 차선자가 그 자리를 대체할 수 있다.</color>","JPN":"<color=#ffd34c>資格を満たさない当主は、その座を次期当主に譲り渡す。</color>","ENG":"<color=#ffd34c>A family leader who is disqualified should be replaced with a proper substitute.</color>","TWN":"<color=#ffd34c>若是堂主不夠資格，則可由第二順位的繼承者取而代之。</color>"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"현 나나하라 당주는 지금껏 직계 후손으로서 무녀의 자격을 증명하지 못했습니다.","JPN":"現当主は今まで直系の子孫として、巫女の資格を証明していません。","ENG":"The current Nanahara family leader has failed to prove herself as a qualified priestess.","TWN":"然而，現任七原的堂主，至今都未能證明其作為直系後裔巫女的資格。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"3년 전에는 바람에게 들었다던 예견이 실패로 돌아갔고……","JPN":"3年前は風の声の予言も失敗に終わり……","ENG":"The prophecy she heard from the wind three years ago failed...","TWN":"3年前從風聲中聽到的預言以失敗收場……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"지금은 여전히 바람의 목소리로부터 해답을 찾지 못하고 계시지요.","JPN":"今もなお、風の声から答えを得られずにいます。","ENG":"And she still hasn’t found the answer from the voice of wind thereafter.","TWN":"至今仍未能在風聲中找到答案。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만 그것이 당주를 끌어내릴 명분이 되지 못합니다.","JPN":"ですが、それだけでは当主の座を譲り渡す理由にはなりません。","ENG":"But that cannot be a reason to impeach the family leader.","TWN":"但這不足以成為要堂主退位的理由。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"장로께선 어찌 3년이 지난 지금에서야 그런 말씀을 꺼내시는지 모르겠군요.","JPN":"長老はなぜ3年も前の出来事を今になって持ち出したのか、理解できませんね。","ENG":"You’ve kept your silence for the last three years. Why bring it up now?","TWN":"而且，長老爲何在3年後的今天才說出種話呢？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"그야 그날을 기점으로 당주님께서 변하셨기 때문이지요.","JPN":"それは、あの日をきっかけにご当主が変わってしまったからです。","ENG":"That’s because Lady Nanahara changed from that day.","TWN":"那是因爲，從那天起堂主就變了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L29_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"물론 3년 전의 오로치 추방이 실패로 돌아간 것을 당주님의 탓으로 돌릴 수는 없습니다.","JPN":"もちろん、3年前のオロチ追放が失敗したことについて、ご当主のせいにすることはできません。","ENG":"I’m not accusing her of the failure to purge Orochi three years ago.","TWN":"當然不能將3年前驅逐大蛇失敗一事，全歸咎到堂主身上。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"하지만 그 수많은 희생에 대한 책임이 없다고는 할 수 없지요.","JPN":"だが、数多くの犠牲に対する責任がないとは限りません。","ENG":"But, she's not entirely blameless for all the lives lost on that day.","TWN":"但是造成那麼多的犧牲，堂主也不能說都沒有責任。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"지금껏 바람의 목소리에서 해답을 찾고 계시지 못하는 것 또한 당주님의 책임은 아닙니다.","JPN":"今まで風の声から答えを得られていないこともご当主の責任ではありません。","ENG":"Also, I wouldn’t say it’s her fault that the voice of wind still hasn’t given her the answer we seek.","TWN":"雖然至今仍無法在風聲中找到答案，這也不是堂主的責任。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"그러나 선견지명이 가장 필요한 시기에, 고작 나유카 가문의 그 방계 꼬마 하나를 찾겠다고 오랫동안 자릴 비우신 것도 사실이지 않습니까?","JPN":"しかし、先見の明が最も必要な時期に、たかが奈由香家の傍系である小僧を探すためだけに席を外していたのも事実。","ENG":"But when we most needed her foresight, she left her post to find that Nayuka boy, who is nothing but a descendant of the collateral family.","TWN":"但是，就在聯盟最需要先見之明的時候，堂主竟然因為要尋找南裕夏家族的旁系小鬼，就離開崗位許久，這也是事實不是嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NULL","text":{"KOREA":"그 배신자 가문의 여식을 품고 감싸는 것에 대해서도 연합원들은 불만을 갖고 있습니다.","JPN":"さらに裏切り者の一族の子孫をかばうことに対しても、連合員は不満を持っています。","ENG":"She also covered up for the traitor’s daughter, which caused discontent among the Alliance members.","TWN":"對於袒護叛徒的女兒一事，聯盟成員也都非常不滿。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"말씀대로, 나나하라 당주께선 지금 온전히 책임을 다할 수 있는 상태가 아니십니다.","JPN":"おっしゃるとおり、七原家当主は今、完璧に責任を果たせる状態ではありません。","ENG":"As he said, Lady Nanahara is not in a state to take full responsibility as the Alliance leader.","TWN":"如您所言，七原堂主現在是失職的狀態。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"연합의 정신적 지주가 되어야 할 나나하라 당주가 연합원들의 불신을 야기하고 있으니, 새로운 적임자가 필요한 때라고 봐야겠지요.","JPN":"連合の精神的支柱となるべき当主が、\\n連合員に不信感を抱かせてしまった。これは新たな適任者が必要な時と考えるべきでしょう。","ENG":"She is supposed to be the unwavering foundation of the Alliance, yet she’s causing conflicts among the members. I agree that we need a new leader.","TWN":"七原堂主原本應該是聯盟的精神支柱，聯盟成員現在卻對堂主感到不信任。那麼，現在就是需要重新選出適任者的時候。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그럼 어쩌자는 거지? 장로님이 새로운 나나하라 당주가 되기라도 하겠다는 거야?","JPN":"じゃあ、どうするっていうんだ？\\n長老が新しい七原の当主にでもなるつもりか？","ENG":"So what are you going to do? Are you planning to be the new leader then?","TWN":"所以你們想怎樣？是要推選長老成爲新任的七原堂主嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"물론 그런 것은 아닙니다. 저 같은 방계가 당주가 되는 건 전통에 어긋나는 일이니까요.","JPN":"無論そんなつもりはありません。\\n私のような傍系が当主になるのは伝統に反します。","ENG":"Of course not. Since I’m from a collateral family, it will be a direct violation of our tradition.","TWN":"當然不是。我出身旁系，成爲堂主是有違傳統的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"하지만 이 자리에 그 조건에 맞는 적임자가 한 사람 있지요.","JPN":"しかし、この場に条件を満たしている者が一人だけいます。","ENG":"But we do have a qualified candidate.","TWN":"不過還有一個符合條件的合適人選。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELDER_NPC_NANAHARA_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나나하라 치후유.","JPN":"七原千冬。","ENG":"Nanahara Chifuyu.","TWN":"七原千冬"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……로군요.","JPN":"……ですね。","ENG":"I see.","TWN":"……嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"기다려주십시오, 장로님.","JPN":"お待ちください、長老。","ENG":"Hold on, Elder.","TWN":"先等一下，長老。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그건 당치도 않습니다. 당주를 지켜야 할 호위무사가 당주 자리에 선다니요.","JPN":"ありえません。当主を守るべき護衛が当主になるなんて。","ENG":"That’s just wrong. I am her bodyguard. I cannot be the family leader.","TWN":"這怎麼可以！護衛武士的本份保護堂主，怎麼可以坐上堂主之位！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"지난 번에도 말씀드렸을 텐데요?","JPN":"前回申し上げたではありませんか。","ENG":"I already told you.","TWN":"我上次不是跟你說過？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그대는 호위무사이기 이전에, 나나하라의 자손이기도 합니다.","JPN":"そなたは護衛である以前に、七原の子孫です。","ENG":"You may be a bodyguard, but you’re also a direct descendant of Nanahara.","TWN":"你雖是護衛武士，但也是七原的子孫。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"또한 그대가 바람의 목소리를 들을 수 있음을 증명한다면, 차기 당주로서의 자격은 충분한 것으로 봐도 되겠지요.","JPN":"そなたが風の声を聞けることを我々に証明出来れば、\\n次期当主としての資格は十分満たしているといえるでしょう。","ENG":"If you can hear the voice of wind, you are qualified to be the next family leader.","TWN":"此外，只要能證明你能聽到風聲，便具備堂主的資格。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"자격을 증명한다면…… 그때는 그대가 원하는 선택을 할 수 있겠죠.","JPN":"資格が証明できれば……そなたが望む選択をすることができるかもしれません。","ENG":"If you prove yourself... you’ll be able to make any decision you want.","TWN":"等到證明資格後……你可以再決定要怎麼做。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그렇게 생각하시지 않습니까?","JPN":"そうは思いませんか？","ENG":"Don’t you agree?","TWN":"你不這麼認爲嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"잠깐만. 그럼 고작 찬반 투표 따위로 새 당주를 결정하겠다는 말이야?","JPN":"ちょっと待て。まさか多数決なんかで新しい当主を決めるつもりか？","ENG":"Wait, so we’re electing a new family leader only with a simple vote?","TWN":"等一下，現在是要只靠投票來決定新任堂主的意思嗎？"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"아뇨. 이 의결은 자격을 증명하기 위한 과정일 뿐입니다.","JPN":"いいえ。この議決は資格を証明するための過程に過ぎません。","ENG":"No, this meeting is to see if the candidate is qualified to be the family leader.","TWN":"不，這個表決只是證明有無資格的過程而已。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그 다음은 현 당주와 후보 당주가 스스로 시험대에 올라 경합을 치러야겠죠.","JPN":"その後、現当主と候補の当主が自ら競い合わなければなりません。","ENG":"The election will be held after. The current leader and the candidate will compete against each other.","TWN":"接下來，現任堂主就要和候選堂主展開競爭。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……알겠습니다.","JPN":"……承知しました。","ENG":"I see.","TWN":"……好。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당주 나나하라 치나츠. 장로님들의 뜻을 따르도록 하죠.","JPN":"当主、七原千夏。長老の皆様の意思に従うことにしましょう。","ENG":"I, Nanahara Chinatsu, accept your suggestion.","TWN":"堂主 七原千夏，願意聽從長老們的意見。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 그것만은 알아주세요.","JPN":"ですが、これだけはわかってください。","ENG":"But please remember this one thing.","TWN":"但是請記住。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"제가 당주의 자리를 양보하게 되더라도, 저는 제 책임을 포기하지 않을 것입니다.","JPN":"当主の座を譲ることになったとしても、私は最後まで自分の責任を果たすつもりです。","ENG":"Even if I’m relieved of my title, I will not give up on my duty.","TWN":"即使我讓出堂主的位子，我也不會放棄我的責任。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"뭐? 그러면 의결은 결과가 어떻게 된 거야?","JPN":"それで？　議決の結果はどうなったんだ？","ENG":"Huh? How did the vote go then?","TWN":"什麼？那表決的結果如何？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"……동표가 나왔어. 아침이 밝는 대로 의결을 할 거다.","JPN":"……同票だった。夜が明けたら、再議決が行われる。","ENG":"The result is a tie. There will be a meeting tomorrow morning.","TWN":"……票數一樣，等天一亮就會進行表決。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하지만 이미 장로들은 답을 정해두고 있어. 의결은 단지 구색 맞춤일 뿐이야.","JPN":"だが、長老たちはすでに答えを決めている。議決は形式的なものにすぎない。","ENG":"But the elders already made up their minds. The meeting is just a show.","TWN":"不過長老們早就有答案了，表決只是做做樣子而已。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"아마 미나토 네가 나유카 가문의 대표로 그 자리에 있었다면 분명한 결과가 나왔겠지만.","JPN":"お前が奈由香家の代表としてその場にいたら、すぐ結果が出てただろうがな。","ENG":"If you participated in the vote as the representative of the Nayuka family, there would have been a decisive result, though.","TWN":"如果你以南裕夏家族代表的身分出席，那應該會有結果吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그렇진 않았을 거야.","JPN":"そんなのわからないよ。","ENG":"I don’t think so.","TWN":"應該不會。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"나한테 투표권이 있다고 해도, 그 자리에 끼어들 수는 없으니까.","JPN":"僕に投票権があったとしても、首を突っ込むことはできなかったと思う。","ENG":"Even if I had the right to vote, I wouldn’t have voted anyways.","TWN":"就算我有投票權，我也不能插手。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"응? 무슨 소리야, 미나토.","JPN":"はあ？　湊、それはどういう意味だ？","ENG":"Huh? What do you mean, Minato?","TWN":"嗯？你這什麼意思？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"넌 당주님을 돕고 싶은 거 아니었어?","JPN":"お前は七原家の当主を助けたいんじゃなかったのか？","ENG":"I thought you wanted to help her.","TWN":"你不是想幫堂主嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"난 연합과 함께 이 도시를 지키러 온 거니까.","JPN":"僕は連合と一緒にこの都市を守るために来たんだ。","ENG":"I’m only here to help the city with the Alliance.","TWN":"我是來和聯盟一起守護這個城市的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이 안에서 누군가와 편을 들며 갈등이나 일으키고 싶진 않아.","JPN":"その中で誰かと手を組み、和を乱すことはしたくない。","ENG":"I’m not going to take somebody’s side and cause disputes.","TWN":"沒有想選邊站惹麻煩的意思。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그거 참…… 미나토다운 대답이네.","JPN":"まったく、湊らしい答えだぜ。","ENG":"That’s... very like you.","TWN":"這……完全是你會回答的答案。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"넌, 옛날부터 늘 그렇게 선을 긋곤 했지.","JPN":"お前は昔からいつもそうやって一歩下がったところから見てたよな。","ENG":"You never step out of your boundary.","TWN":"你以前就是這樣與人劃清界限。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"평범하게 지내려면, 남의 일에 휘말리지 않는 게 좋다면서 말이야.","JPN":"平凡に暮らすためには、他人事に巻き込まれない方がいい、だっけ？","ENG":"You always said you wanted to be ordinary, never interfering in anyone’s business.","TWN":"要想過平凡的生活，最好不要插手別人的事情。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"따라와.","JPN":"ついて来い。","ENG":"Come with me.","TWN":"跟我來。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응? 어디 가는데?","JPN":"えっ？　どこに行くの？","ENG":"Huh? Where?","TWN":"嗯？要去哪裡？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"눈 좀 붙여야지.","JPN":"ちょっと休んだほうがいい。","ENG":"You have to get some sleep.","TWN":"小睡一下吧。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"너, 하루 종일 잠도 못 자고 싸웠잖냐.","JPN":"お前、昨日から一睡もせずに戦ってただろ？","ENG":"You haven’t rested at all today, fighting monsters.","TWN":"你不是整天沒睡都在戰鬥嗎！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};